import{_ as i,o as a,c as t,a0 as s}from"./chunks/framework.DTwdCQre.js";const k=JSON.parse('{"title":"LSP Integration","description":"LSP health checks, capability gating, diagnostics, and fallback behavior","frontmatter":{"title":"LSP Integration","description":"LSP health checks, capability gating, diagnostics, and fallback behavior"},"headers":[],"relativePath":"extension/lsp.md","filePath":"extension/lsp.md","lastUpdated":1777727293000}'),n={name:"extension/lsp.md"};function o(r,e,l,d,h,c){return a(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="lsp-integration" tabindex="-1">LSP Integration <a class="header-anchor" href="#lsp-integration" aria-label="Permalink to &quot;LSP Integration&quot;">​</a></h1><blockquote><p><strong>Status: Experimental (v0.3 productization)</strong> — The LSP client and health gate are implemented, but LSP-powered code intelligence is exposed only after a configured server passes a health check. <code>go-code doctor --offline</code> reports local configuration without starting network probes.</p></blockquote><p>go-code uses Language Server Protocol (LSP) support as an optional extension surface for code intelligence. The core prompt, TUI, built-in tools, MCP tools, hooks, and skills continue to work when no LSP server is configured.</p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>LSP health checks are opt-in through <code>GO_CODE_LSP_URL</code>:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> GO_CODE_LSP_URL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http://127.0.0.1:8080/lsp&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>When the variable is not set, LSP is treated as unavailable rather than failed.</p><h2 id="health-checks" tabindex="-1">Health Checks <a class="header-anchor" href="#health-checks" aria-label="Permalink to &quot;Health Checks&quot;">​</a></h2><p>The LSP gate sends an <code>initialize</code> request before advertising code-intelligence operations. A server is considered healthy only when initialization succeeds.</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go-code</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Offline diagnostics do not contact the server:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go-code</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --offline</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Expected doctor states:</p><table tabindex="0"><thead><tr><th>State</th><th>Meaning</th></tr></thead><tbody><tr><td><code>[SKIP] lsp: not configured</code></td><td><code>GO_CODE_LSP_URL</code> is unset.</td></tr><tr><td><code>[SKIP] lsp: configured ... skipped by --offline</code></td><td>LSP URL is present, but network health was intentionally skipped.</td></tr><tr><td><code>[PASS] lsp</code></td><td>Initialization succeeded.</td></tr><tr><td><code>[FAIL] lsp</code></td><td>A configured server failed initialization or returned an invalid response.</td></tr></tbody></table><h2 id="capability-gating" tabindex="-1">Capability Gating <a class="header-anchor" href="#capability-gating" aria-label="Permalink to &quot;Capability Gating&quot;">​</a></h2><p>go-code advertises LSP operations only after the health check passes. The gate currently recognizes:</p><table tabindex="0"><thead><tr><th>Operation</th><th>LSP capability</th></tr></thead><tbody><tr><td>Diagnostics</td><td><code>publishDiagnosticsProvider</code></td></tr><tr><td>Symbols</td><td><code>workspaceSymbolProvider</code> or <code>documentSymbolProvider</code></td></tr><tr><td>Definitions</td><td><code>definitionProvider</code></td></tr><tr><td>References</td><td><code>referencesProvider</code></td></tr><tr><td>Hover</td><td><code>hoverProvider</code></td></tr></tbody></table><p>If the server is not configured, cannot initialize, or does not advertise a capability, the corresponding operation remains unavailable.</p><h2 id="trace-evidence" tabindex="-1">Trace Evidence <a class="header-anchor" href="#trace-evidence" aria-label="Permalink to &quot;Trace Evidence&quot;">​</a></h2><p>LSP health outcomes are recorded as non-fatal extension events in the session trace:</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;extension&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;lsp&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;event&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;health_check&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;status&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;unavailable&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Successful checks include advertised operations and server identity when provided. Failed checks record the initialization error without stopping unrelated workflows.</p><h2 id="fallback-behavior" tabindex="-1">Fallback Behavior <a class="header-anchor" href="#fallback-behavior" aria-label="Permalink to &quot;Fallback Behavior&quot;">​</a></h2><ul><li>No LSP config: continue without LSP operations.</li><li>Offline doctor: report configuration state without network access.</li><li>Initialization failure: keep core prompt/tool workflows available and report the LSP failure through diagnostics and trace evidence.</li><li>Missing server capability: do not advertise that operation.</li></ul><h2 id="verification" tabindex="-1">Verification <a class="header-anchor" href="#verification" aria-label="Permalink to &quot;Verification&quot;">​</a></h2><p>Current coverage lives in <code>internal/lsp/gate_test.go</code> and proves unavailable, initialization success, initialization failure, trace recording, and operation gating behavior.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./mcp.html">MCP Integration</a></li><li><a href="./hooks.html">Hooks System</a></li><li><a href="./skills.html">Skills System</a></li></ul>',28)])])}const u=i(n,[["render",o]]);export{k as __pageData,u as default};
